// src/components/ListaTratamentos.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from './context/AuthContext'; // Se quiser mostrar nome do logado caso não venha do backend

export default function ListaTratamentos({ pacienteId, reloadKey = 0, onFinalizar }) {
  const [tratamentos, setTratamentos] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user } = useAuth?.() || {}; // só se for usar fallback do nome

  // Sempre busca tratamentos quando pacienteId OU reloadKey mudar
  useEffect(() => {
    if (!pacienteId) {
      setTratamentos([]);
      setLoading(false);
      return;
    }
    setLoading(true);
    axios
      .get(`/api/tratamentos?paciente_id=${pacienteId}`)
      .then((res) => {
        setTratamentos(res.data || []);
        console.log("Tratamentos carregados:", res.data);
      })
      .catch((err) => {
        setTratamentos([]);
        console.log("Erro ao carregar tratamentos:", err);
      })
      .finally(() => setLoading(false));
  }, [pacienteId, reloadKey]);

  function handleFinalizar(id) {
    setTratamentos((prev) =>
      prev.map((t) =>
        t.id === id ? { ...t, status: "finalizado" } : t
      )
    );
    if (onFinalizar) onFinalizar(id);
  }

  return (
    <div className="bg-white rounded shadow p-4 mb-6">
      <h3 className="text-lg font-semibold mb-2">Tratamentos</h3>
      {loading ? (
        <div className="text-center text-gray-400 py-10">
          <p className="mb-2 text-lg">Carregando tratamentos...</p>
        </div>
      ) : tratamentos.length === 0 ? (
        <div className="text-center text-gray-400 py-10">
          <p className="mb-2 text-lg">Nenhum tratamento cadastrado ainda.</p>
          <span className="text-xs text-gray-400">Comece adicionando um tratamento acima.</span>
        </div>
      ) : (
        <table className="w-full text-sm">
          <thead>
            <tr className="bg-gray-50">
              <th>Tratamento</th>
              <th>Dente</th>
              <th>Profissional</th>
              <th>Status</th>
              <th></th>
            </tr>
          </thead>
          <tbody>
            {tratamentos.map((t) => (
              <tr key={t.id}>
                <td>{t.tratamento}</td>
                <td>{t.dente}</td>
                <td>
                  {/* Aqui tenta mostrar o nome, senão mostra o ID do aluno/profissional */}
                  {t.profissional || user?.nome || t.aluno_id || "-"}
                </td>
                <td>
                  {t.status === "aberto" ? (
                    <span className="text-yellow-600">Aberto</span>
                  ) : (
                    <span className="text-green-600">Finalizado</span>
                  )}
                </td>
                <td>
                  {t.status === "aberto" && (
                    <button
                      className="text-xs bg-green-500 text-white px-2 py-1 rounded"
                      onClick={() => handleFinalizar(t.id)}
                    >
                      Finalizar
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}
